package com.veetu.vadagai.payment;import com.veetu.vadagai.common.BaseEntity;import com.veetu.vadagai.property.Property;import com.veetu.vadagai.user.User;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDate;
@Entity @Table(indexes={@Index(name="idx_payment_payer",columnList="payer_id"),@Index(name="idx_payment_property",columnList="property_id")}) @Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor public class Payment extends BaseEntity{ @ManyToOne(optional=false) @JoinColumn(name="payer_id") private User payer; @ManyToOne(optional=false) private Property property; @Enumerated(EnumType.STRING) @Column(nullable=false) private PaymentType type; @Enumerated(EnumType.STRING) @Column(nullable=false) private PaymentStatus status; @Column(nullable=false,precision=12,scale=2) private BigDecimal amount; private BigDecimal lateFee; @Column(nullable=false) private LocalDate dueDate; private String gatewayOrderId; private String gatewayPaymentId; private String receiptUrl; }
